const e=JSON.parse('{"key":"v-8ddacc14","path":"/complain_diary/2024_07_01.html","title":"我的前端之路(二)","lang":"zh-CN","frontmatter":{"article":false,"title":"我的前端之路(二)","icon":"face-meh-blank"},"headers":[],"git":{"createdTime":1719830679000,"updatedTime":1719830679000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":3.79,"words":1136},"filePathRelative":"complain_diary/2024_07_01.md","localizedDate":"2024年7月1日","excerpt":"<p>毕业了。回来更新了。</p>\\n<p>我从大二下开始就是以吊着一口气为前提进行生活的，可能是对前途太过于渺茫，所以当时的我希望能多学点东西来找点事情做。我那时很享受学习的过程，世界上有那么多的东西可以学，即使只面对一个方向深钻也会出现学无止境的情况，所以那几年真的很快乐，因为还不用考虑其他的事情。但是一旦意识到学习到一定程度后，在某些时候必须要做出些成果时，我反而有些不知所措。有些像是古话说的“学而不思则罔”。究其原因，还是因为我那时依旧只是一个没安全感，掌控欲强，希望任何经手事都应面面俱到的小孩，对项目总有“做一件事情就要做到极致”的想法，因此一旦有事情不合心意，我便会焦虑、愤懑，然后心惊胆战地向着反方向逃去。然后在同样的经历过许多，许多，许多次之后，我就慢慢的进入到一个苦闷的状态。我不再相信自己能做好什么，开始得过且过，我那时的想法就是很单纯的“能活着就很不错了”。于是以此为前提，我开始找实习。</p>"}');export{e as data};
